# Let's use reflection to discover the API
cd /tmp/sv-599409865f024387a0cbcf9ed5fc3e6b/ResearchAgent
cat > /tmp/api_explorer.cs << 'CSHARP'
using System.Reflection;

var asmPath = Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.agents.ai/1.5.0/lib/net10.0/Microsoft.Agents.AI.dll");
var asmAbsPath = Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.agents.ai.abstractions/1.5.0/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll");

foreach (var p in new[] { asmAbsPath, asmPath })
{
    var asm = Assembly.LoadFrom(p);
    Console.WriteLine($"\n=== {asm.GetName().Name} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        Console.WriteLine($"\n  {t.FullName}");
        foreach (var c in t.GetConstructors())
            Console.WriteLine($"    ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var pr in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    prop {pr.PropertyType.Name} {pr.Name}");
    }
}
CSHARP

