using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Shared state for the note-taking tool ──────────────────────────────────
var notebook = new List<string>();

// ── Define tools as AIFunctions ────────────────────────────────────────────
var searchWebFn = AIFunctionFactory.Create(SearchWebAsync, new AIFunctionFactoryOptions
{
    Name = "search_web",
    Description = "Search the web for information. Returns the top result snippets.",
});

var addNoteFn = AIFunctionFactory.Create(
    [Description("Save a note to the research notebook.")]
    (
        [Description("The note content to save")] string note
    ) =>
    {
        notebook.Add(note);
        return $"Note #{notebook.Count} saved successfully.";
    },
    new AIFunctionFactoryOptions
    {
        Name = "add_note",
        Description = "Save a research note for later reference.",
    });

var readNotesFn = AIFunctionFactory.Create(
    [Description("Read all saved research notes.")]
    () =>
    {
        if (notebook.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < notebook.Count; i++)
            sb.AppendLine($"[Note #{i + 1}] {notebook[i]}");
        return sb.ToString();
    },
    new AIFunctionFactoryOptions
    {
        Name = "read_notes",
        Description = "Read all previously saved research notes.",
    });

// ── Build services ─────────────────────────────────────────────────────────
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
var sp = services.BuildServiceProvider();

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "Researches topics by searching the web and summarizing findings.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
        Tools = [searchWebFn, addNoteFn, readNotesFn],
    },
    ChatHistoryProvider = new InMemoryChatHistoryProvider(),
};

var agent = new ChatClientAgent(
    chatClient,
    agentOptions,
    sp.GetRequiredService<ILoggerFactory>(),
    sp);

// ── Prompt the user ────────────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ──────────────────────────────────────────────────────────
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"""
    Research the following topic thoroughly: "{topic}"

    Follow these steps:
    1. Search the web 2-3 times with varied queries to gather diverse information.
    2. After each search, use the add_note tool to record key findings.
    3. Once you have gathered enough information, use read_notes to review everything.
    4. Produce a well-structured summary with:
       - An overview of the topic
       - Key facts and details
       - Different perspectives or notable points

    Be thorough but concise. Cite sources where possible.
    """,
    session))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// ── Web search tool implementation ─────────────────────────────────────────
[Description("Search the web for information on a given query.")]
static async Task<string> SearchWebAsync(
    [Description("The search query string")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
    http.Timeout = TimeSpan.FromSeconds(15);

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url, cancellationToken);

        var results = new StringBuilder();
        results.AppendLine($"Search results for: \"{query}\"\n");

        // Extract result titles and snippets from DuckDuckGo HTML
        var resultPattern = ResultRegex();
        var matches = resultPattern.Matches(html);

        var count = 0;
        foreach (Match match in matches)
        {
            if (count >= 5) break;

            var title = StripHtml(match.Groups["title"].Value).Trim();
            var snippet = StripHtml(match.Groups["snippet"].Value).Trim();
            var resultUrl = match.Groups["url"].Value.Trim();

            if (string.IsNullOrWhiteSpace(title) && string.IsNullOrWhiteSpace(snippet))
                continue;

            count++;
            results.AppendLine($"{count}. {title}");
            if (!string.IsNullOrWhiteSpace(resultUrl))
                results.AppendLine($"   URL: {resultUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                results.AppendLine($"   {snippet}");
            results.AppendLine();
        }

        if (count == 0)
        {
            // Fallback: extract any snippet-class text
            var snippetPattern = SnippetRegex();
            var snippetMatches = snippetPattern.Matches(html);
            foreach (Match m in snippetMatches)
            {
                if (count >= 5) break;
                var text = StripHtml(m.Groups[1].Value).Trim();
                if (!string.IsNullOrWhiteSpace(text))
                {
                    count++;
                    results.AppendLine($"{count}. {text}");
                    results.AppendLine();
                }
            }
        }

        return count > 0
            ? results.ToString()
            : $"No results found for \"{query}\".";
    }
    catch (Exception ex)
    {
        return $"Search failed for \"{query}\": {ex.Message}";
    }
}

static string StripHtml(string html)
{
    var text = HtmlTagRegex().Replace(html, string.Empty);
    text = text.Replace("&amp;", "&")
               .Replace("&lt;", "<")
               .Replace("&gt;", ">")
               .Replace("&quot;", "\"")
               .Replace("&#39;", "'")
               .Replace("&nbsp;", " ");
    return WhitespaceRegex().Replace(text, " ").Trim();
}

