// ── Define tools as AIFunctions ────────────────────────────────────────────
var searchWebFn = AIFunctionFactory.Create(SearchWebAsync, new AIFunctionFactoryOptions
{
    Name = "search_web",
    Description = "Search the web for information. Returns the top result snippets.",
});

var addNoteFn = AIFunctionFactory.Create(
    [Description("Save a note to the research notebook.")]
    (
        [Description("The note content to save")] string note
    ) =>
    {
        notebook.Add(note);
        return $"Note #{notebook.Count} saved successfully.";
    },
    new AIFunctionFactoryOptions
    {
        Name = "add_note",
        Description = "Save a research note for later reference.",
    });

var readNotesFn = AIFunctionFactory.Create(
    [Description("Read all saved research notes.")]
    () =>
    {
        if (notebook.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < notebook.Count; i++)
            sb.AppendLine($"[Note #{i + 1}] {notebook[i]}");
        return sb.ToString();
    },
    new AIFunctionFactoryOptions
    {
        Name = "read_notes",
        Description = "Read all previously saved research notes.",
    });

// ── Build services ─────────────────────────────────────────────────────────
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
var sp = services.BuildServiceProvider();

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "Researches topics by searching the web and summarizing findings.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
        Tools = [searchWebFn, addNoteFn, readNotesFn],
    },
    ChatHistoryProvider = new InMemoryChatHistoryProvider(),
};

var agent = new ChatClientAgent(
    chatClient,
    agentOptions,
    sp.GetRequiredService<ILoggerFactory>(),
    sp);

// ── Prompt the user ────────────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ──────────────────────────────────────────────────────────
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"""
    Research the following topic thoroughly: "{topic}"

    Follow these steps:
    1. Search the web 2-3 times with varied queries to gather diverse information.
    2. After each search, use the add_note tool to record key findings.
    3. Once you have gathered enough information, use read_notes to review everything.
    4. Produce a well-structured summary with:
       - An overview of the topic
       - Key facts and details
       - Different perspectives or notable points

    Be thorough but concise. Cite sources where possible.
    """,
    session))
{
