// ── Web search tool implementation ─────────────────────────────────────────
[Description("Search the web for information on a given query.")]
static async Task<string> SearchWebAsync(
    [Description("The search query string")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
    http.Timeout = TimeSpan.FromSeconds(15);

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url, cancellationToken);

        var results = new StringBuilder();
        results.AppendLine($"Search results for: \"{query}\"\n");

        // Extract result titles and snippets from DuckDuckGo HTML
        var resultPattern = ResultRegex();
        var matches = resultPattern.Matches(html);

        var count = 0;
        foreach (Match match in matches)
        {
            if (count >= 5) break;

            var title = StripHtml(match.Groups["title"].Value).Trim();
            var snippet = StripHtml(match.Groups["snippet"].Value).Trim();
            var resultUrl = match.Groups["url"].Value.Trim();

            if (string.IsNullOrWhiteSpace(title) && string.IsNullOrWhiteSpace(snippet))
                continue;

            count++;
            results.AppendLine($"{count}. {title}");
            if (!string.IsNullOrWhiteSpace(resultUrl))
                results.AppendLine($"   URL: {resultUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                results.AppendLine($"   {snippet}");
            results.AppendLine();
        }

        if (count == 0)
        {
            // Fallback: extract any snippet-class text
            var snippetPattern = SnippetRegex();
            var snippetMatches = snippetPattern.Matches(html);
            foreach (Match m in snippetMatches)
            {
                if (count >= 5) break;
                var text = StripHtml(m.Groups[1].Value).Trim();
                if (!string.IsNullOrWhiteSpace(text))
                {
                    count++;
                    results.AppendLine($"{count}. {text}");
                    results.AppendLine();
                }
            }
        }

        return count > 0
            ? results.ToString()
            : $"No results found for \"{query}\".";
    }
    catch (Exception ex)
    {
        return $"Search failed for \"{query}\": {ex.Message}";
    }
}

static string StripHtml(string html)
{
    var text = HtmlTagRegex().Replace(html, string.Empty);
    text = text.Replace("&amp;", "&")
               .Replace("&lt;", "<")
               .Replace("&gt;", ">")
               .Replace("&quot;", "\"")
               .Replace("&#39;", "'")
               .Replace("&nbsp;", " ");
    return WhitespaceRegex().Replace(text, " ").Trim();
}

