129.     using var http = new HttpClient();
130.     http.DefaultRequestHeaders.UserAgent.ParseAdd(
131.         "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
132.     http.Timeout = TimeSpan.FromSeconds(15);
133. 
134.     try
